			originalCosts[i] = dispatch.Assigns[i].Cost
		}
		candidateIndices := make([]int, 0, nextAssignIdx+1)
		for i := 0; i < nextAssignIdx; i++ {
			candidateIndices = append(candidateIndices, i)
		}
		rand.Shuffle(len(candidateIndices), func(i, j int) {
			candidateIndices[i], candidateIndices[j] = candidateIndices[j], candidateIndices[i]
		})
		for _, idx := range candidateIndices {
			ok := dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					marginal := dispatch.Assigns[idx].Cost - originalCosts[idx]
					if marginal < bestMarginalCost {
						bestMarginalCost = marginal
						bestAssignIdx = idx
					}
				}
				dispatch.Assigns[idx].RemoveShip(total_ship + jj)
				dispatch.Assigns[idx].GenRoute()
			}
		}
		fallbackIdx := -1
		if bestAssignIdx == -1 {
			fallbackIdx = nextAssignIdx
			if fallbackIdx < MAXASSIGNS {
